code_changes.content:
[
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Inverted condition for handling input variables during validate walk. The code returns unknown values when NOT in validate walk, but the comment and logic require the opposite: unknown values should be returned DURING validate walk to test all possible inputs, while actual values should be returned during plan/apply walks. This breaks the fundamental purpose of the validate walk and causes incorrect variable resolution during planning.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Inverted logic for ephemeral variable marking. The code marks values as ephemeral when cfg.Ephemeral is FALSE (!cfg.Ephemeral), but the comment and semantics require the opposite: ephemeral variables (cfg.Ephemeral == true) should be marked as ephemeral. The else block then incorrectly prevents ephemeral values from being assigned to non-ephemeral variables. This inverts the entire ephemeral variable semantics.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,7 +189,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *I
 		}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
"
  },
  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "NilHook.PreApply returns HookActionHalt instead of HookActionContinue. NilHook is designed as a no-op hook implementation that does nothing, allowing custom hooks to embed it and override only needed methods. By returning HookActionHalt, this breaks the contract - any hook that embeds NilHook without overriding PreApply will halt all apply operations. All other NilHook methods correctly return HookActionContinue, making this inconsistency a critical functional bug.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -135,7 +135,7 @@ var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  }
]

